package com.example.sso.controller;

import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Arrays;
import java.util.List;

@Controller
public class LogoutController {

    private static final List<String> ALLOWED_DOMAINS = Arrays.asList(
            "example.com",
            "app.example.com",
            "portal.example.com",
            "admin.example.com"
    );

    private static final String DEFAULT_REDIRECT = "/login";

    @GetMapping("/logout")
    public void logout(
            @RequestParam(value = "next", required = false) String next,
            HttpServletRequest request,
            HttpServletResponse response) throws IOException {

        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        String redirectUrl = validateAndSanitizeRedirectUrl(next, request);
        response.sendRedirect(redirectUrl);
    }

    private String validateAndSanitizeRedirectUrl(String next, HttpServletRequest request) {
        if (next == null || next.trim().isEmpty()) {
            return request.getContextPath() + DEFAULT_REDIRECT;
        }

        try {
            if (next.startsWith("/")) {
                return request.getContextPath() + next;
            }

            URI uri = new URI(next);
            
            if (uri.getScheme() == null || uri.getHost() == null) {
                return request.getContextPath() + DEFAULT_REDIRECT;
            }

            String scheme = uri.getScheme().toLowerCase();
            if (!scheme.equals("http") && !scheme.equals("https")) {
                return request.getContextPath() + DEFAULT_REDIRECT;
            }

            String host = uri.getHost().toLowerCase();
            
            boolean isAllowed = ALLOWED_DOMAINS.stream()
                    .anyMatch(allowedDomain -> host.equals(allowedDomain) || host.endsWith("." + allowedDomain));

            if (isAllowed) {
                return next;
            }

        } catch (URISyntaxException e) {
            return request.getContextPath() + DEFAULT_REDIRECT;
        }

        return request.getContextPath() + DEFAULT_REDIRECT;
    }
}